// Two-phase work:
// Phase A: enqueue NEW failures not already in the queue (dedup by source_table+source_id)
// Phase B: process queue rows where next_retry_at <= now

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const failedEmails  = allOf('Failed Emails 60m');
const failedMsgs    = allOf('Failed Messages 60m');
const pendingQueue  = allOf('Pending Queue');

// Build a set of already-queued source rows so we don't double-enqueue
const queuedKeys = new Set();
pendingQueue.forEach(function (q) {
  if (q && q.source_table && q.source_id) {
    queuedKeys.add(q.source_table + ':' + q.source_id);
  }
});

const BACKOFF_MINUTES = [5, 15, 60]; // 1st retry: 5 min, 2nd: 15 min, 3rd: 60 min

function nextRetryISO(retryCount) {
  const minutes = BACKOFF_MINUTES[retryCount] || BACKOFF_MINUTES[BACKOFF_MINUTES.length - 1];
  return new Date(Date.now() + minutes * 60000).toISOString();
}

// Phase A: enqueue
const newEnqueues = [];
failedEmails.forEach(function (e) {
  if (!e || !e.id) return;
  const key = 'email_log:' + e.id;
  if (queuedKeys.has(key)) return;
  newEnqueues.push({
    source_table: 'email_log',
    source_id: e.id,
    channel: 'email',
    recipient: e.recipient,
    payload: { subject: e.subject, original_status: e.status },
    retry_count: 0,
    max_retries: 3,
    next_retry_at: nextRetryISO(0),
    last_error: e.status,
    status: 'pending'
  });
});
failedMsgs.forEach(function (m) {
  if (!m || !m.id) return;
  const key = 'messages_sent:' + m.id;
  if (queuedKeys.has(key)) return;
  newEnqueues.push({
    source_table: 'messages_sent',
    source_id: m.id,
    channel: (m.channel || 'other').toLowerCase(),
    recipient: m.recipient,
    payload: { channel: m.channel, original_status: m.status, original_error: m.error },
    retry_count: 0,
    max_retries: 3,
    next_retry_at: nextRetryISO(0),
    last_error: m.error || m.status,
    status: 'pending'
  });
});

// Phase B: process due retries
const nowMs = Date.now();
const dueRows = pendingQueue.filter(function (q) {
  if (!q || !q.next_retry_at) return false;
  return new Date(q.next_retry_at).getTime() <= nowMs;
});

const retryActions = [];
const exhausted = [];
const statusUpdates = [];

dueRows.forEach(function (q) {
  const nextCount = (q.retry_count || 0) + 1;
  if (nextCount > (q.max_retries || 3)) {
    // Exhausted retries — mark permanent_failure
    exhausted.push({
      id: q.id,
      patch: {
        status: 'permanent_failure',
        resolved_at: new Date().toISOString(),
        resolution: 'max_retries_exceeded'
      },
      source: q
    });
  } else {
    // Schedule the retry — flip the originating lead back to Outreach Ready
    // so the existing outreach-sender cron picks it up next cycle.
    retryActions.push({
      queue_id: q.id,
      lead_id: q.lead_id,
      channel: q.channel,
      recipient: q.recipient,
      next_retry_count: nextCount,
      patch: {
        retry_count: nextCount,
        next_retry_at: nextRetryISO(nextCount),
        status: nextCount >= (q.max_retries || 3) ? 'pending' : 'pending',
        last_error: q.last_error
      }
    });
  }
});

return { json: {
  measured_at: new Date().toISOString(),
  enqueue_count: newEnqueues.length,
  retry_count: retryActions.length,
  exhausted_count: exhausted.length,
  new_enqueues: newEnqueues,
  retry_actions: retryActions,
  exhausted: exhausted,
  alerts: exhausted.map(function (e) {
    return {
      module_name: 'cost_monitoring',
      alert_type: 'outreach_permanent_failure',
      severity: 'warning',
      title: 'Outreach permanently failed after ' + (e.source.max_retries || 3) + ' retries',
      message: 'Recipient ' + (e.source.recipient || 'unknown') + ' on channel ' + (e.source.channel || 'unknown') + ' failed all ' + (e.source.max_retries || 3) + ' retry attempts. Last error: ' + (e.source.last_error || 'unknown'),
      details: { queue_row: e.source },
      status: 'open',
      aggregation_key: 'outreach_permanent:' + (e.source.lead_id || e.source.recipient || e.source.id)
    };
  })
} };
